import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';

/**
 * Handle user updated event — notify user of account changes.
 */
private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
  const changesDescription = event.changes.join(', ');

  await this.sendNotification({
    type: 'user-updated',
    channel: 'email',
    recipient: event.user.email,
    userId: event.user.id,
    subject: 'Your Account Has Been Updated',
    body: `The following fields on your account have been updated: ${changesDescription}.`,
  });
}

